command:
// ======================================
// 异常结算样板宏：最大生命值比例伤害
// ======================================
// 当异常值满槽时自动执行，对目标造成其最大生命值十分之一的伤害。
// 使用 PF2e 系统原生的 DamageRoll + applyDamage 方法结算。
// 使用方法：复制此宏到宏目录，修改下方配置，然后在遗名之穹配置中关联。
// 传入参数：{ actor, token, speaker, damageType }
// ======================================

// ===== 用户配置区域 =====
const HP_FRACTION = 0.1;            // 最大生命值的比例（0.1 = 十分之一，0.25 = 四分之一）
const DAMAGE_TYPE = damageType;     // 伤害类型，默认使用触发的异常类型
const ROUND_MODE = "floor";         // 取整方式："floor"（向下取整）、"ceil"（向上取整）、"round"（四舍五入）
// ===== 配置结束 =====

if (!actor) {
  ui.notifications.warn("异常结算宏：未找到目标角色");
  return;
}

try {
  const maxHp = actor.system?.attributes?.hp?.max ?? 0;
  if (maxHp <= 0) {
    ui.notifications.warn("异常结算宏：目标角色最大生命值无效");
    return;
  }

  // 计算比例伤害
  let totalDamage;
  if (ROUND_MODE === "ceil") {
    totalDamage = Math.ceil(maxHp * HP_FRACTION);
  } else if (ROUND_MODE === "round") {
    totalDamage = Math.round(maxHp * HP_FRACTION);
  } else {
    totalDamage = Math.floor(maxHp * HP_FRACTION);
  }
  totalDamage = Math.max(1, totalDamage); // 至少造成 1 点伤害

  // 获取伤害类型的本地化名称
  const typeLabel = CONFIG?.PF2E?.damageTypes?.[DAMAGE_TYPE]
    ? game.i18n.localize(CONFIG.PF2E.damageTypes[DAMAGE_TYPE])
    : DAMAGE_TYPE;
  const percentLabel = `${Math.round(HP_FRACTION * 100)}%`;

  // 使用 PF2e 原生 DamageRoll 构建带伤害类型的骰子
  const DamageRollClass = CONFIG.Dice.rolls.find(r => r.name === "DamageRoll");
  if (DamageRollClass) {
    // 使用固定数值作为伤害公式
    const formula = `{${totalDamage}[${DAMAGE_TYPE}]}`;
    const roll = new DamageRollClass(formula);
    await roll.evaluate();

    // 发送伤害骰子消息到聊天
    await roll.toMessage({
      speaker,
      flavor: `<strong>异常结算</strong>：${actor.name} 的 ${typeLabel} 异常值已满！<br>最大 HP ${percentLabel}（${maxHp} × ${HP_FRACTION} = ${totalDamage}）`
    });

    // 使用系统原生 applyDamage 结算
    const tokenDoc = token?.document ?? token;
    await actor.applyDamage({ damage: roll, token: tokenDoc });
  } else {
    // Fallback：非 PF2e 系统
    const currentHp = actor.system?.attributes?.hp?.value ?? 0;
    const newHp = Math.max(0, currentHp - totalDamage);
    await actor.update({ "system.attributes.hp.value": newHp });

    const content = `
      <div style="padding: 6px; border-left: 3px solid #d63384; background: #fdf2f8; border-radius: 3px;">
        <p style="margin: 0; font-size: 0.9em;"><strong>异常结算</strong>：${actor.name} 受到最大 HP ${percentLabel}（${totalDamage}）点 ${typeLabel} 伤害。</p>
      </div>
    `;
    await ChatMessage.create({ speaker, content });
  }

} catch (err) {
  console.error("异常结算宏执行失败:", err);
  ui.notifications.error("异常结算宏执行失败，请查看控制台");
}
